import redis
import json
import sys

class RedisLuaClient:
    def __init__(self, host='localhost', port=6379, db=0, password=None):
        self.client = redis.Redis(
            host=host,
            port=port,
            db=db,
            password=password,
            decode_responses=True
        )
    
    def execute_lua_script(self, script, keys=None, args=None):
        if keys is None:
            keys = []
        if args is None:
            args = []
        
        result = self.client.eval(script, len(keys), *keys, *args)
        return result
    
    def execute_lua_with_params(self, script, params):
        keys = params.get('keys', [])
        args = params.get('args', [])
        return self.execute_lua_script(script, keys, args)
    
    def run_interactive(self):
        print("Redis Lua Script Executor")
        print("=" * 50)
        print("Commands:")
        print("  script - Enter a Lua script to execute")
        print("  quit - Exit the program")
        print("=" * 50)
        
        while True:
            command = input("\nEnter command: ").strip().lower()
            
            if command == 'quit':
                break
            elif command == 'script':
                self.execute_user_script()
            else:
                print("Unknown command. Use 'script' or 'quit'")
    
    def execute_user_script(self):
        print("\nEnter your Lua script (end with a line containing only 'END'):")
        script_lines = []
        while True:
            line = input()
            if line.strip() == 'END':
                break
            script_lines.append(line)
        
        script = '\n'.join(script_lines)
        
        keys_input = input("\nEnter keys (comma-separated, or press Enter for none): ").strip()
        keys = [k.strip() for k in keys_input.split(',') if k.strip()] if keys_input else []
        
        args_input = input("Enter args (comma-separated, or press Enter for none): ").strip()
        args = [a.strip() for a in args_input.split(',') if a.strip()] if args_input else []
        
        try:
            result = self.execute_lua_script(script, keys, args)
            print(f"\nResult: {result}")
        except Exception as e:
            print(f"\nError executing script: {e}")


def main():
    host = input("Redis host (default: localhost): ").strip() or 'localhost'
    port = input("Redis port (default: 6379): ").strip() or '6379'
    db = input("Redis database (default: 0): ").strip() or '0'
    password = input("Redis password (press Enter if none): ").strip() or None
    
    try:
        port = int(port)
        db = int(db)
    except ValueError:
        print("Invalid port or database number")
        sys.exit(1)
    
    try:
        client = RedisLuaClient(host=host, port=port, db=db, password=password)
        client.client.ping()
        print("Connected to Redis successfully!")
        client.run_interactive()
    except redis.ConnectionError as e:
        print(f"Failed to connect to Redis: {e}")
        sys.exit(1)
    except Exception as e:
        print(f"Error: {e}")
        sys.exit(1)


if __name__ == "__main__":
    main()